func runCommand(ctx context.Context, command []string, workingDir string, env map[string]string, timeout time.Duration) (stdout bytes.Buffer, stderr bytes.Buffer, exitCode int, startTime time.Time, endTime time.Time, runErr error) {
	ctxWithTimeout, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()

	cmd := exec.CommandContext(ctxWithTimeout, command[0], command[1:]...)
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if workingDir != "" {
		safePath, err := sanitizePath(s.workspaceDir, workingDir)
		if err != nil {
			runErr = fmt.Errorf("invalid working directory: %w", err)
			return
		}
		cmd.Dir = safePath
	}

	if len(env) > 0 {
		cmd.Env = append(cmd.Environ(), envMapToSlice(env)...)
	}

	startTime = time.Now()
	if runErr = cmd.Run(); runErr != nil {
		if exitErr, ok := runErr.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}

		if ctxWithTimeout.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			stderr.WriteString(fmt.Sprintf("\nCommand timed out after %d seconds\n", int(timeout.Seconds())))
		}
		endTime = time.Now()
		return
	}

	exitCode = 0
	endTime = time.Now()
	return
}

