func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required", "code": 400})
		return
	}

	fileHeader, err := c.FormFile("file")
	if err != nil {
