	if _, err := io.Copy(out, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err), "code": 500})
		return
	}

	if err := os.Chmod(safePath, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to set file mode: %v", err), "code": 500})
		return
	}

	relPath, _ := filepath.Rel(s.workspaceDir, safePath)
	if relPath == "" {
		relPath = path
	}

	fileInfo, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     fileInfo.Size(),
		Mode:     fmt.Sprintf("%o", mode),
		Modified: fileInfo.ModTime(),
	})
}

