package picod

import (
	"fmt"
	"path/filepath"
	"strings"
)

func sanitizePath(workspaceDir, requestedPath string) (string, error) {
	if workspaceDir == "" {
		return "", fmt.Errorf("workspace directory not initialized")
	}

	resolvedWorkspace, err := filepath.EvalSymlinks(workspaceDir)
	if err != nil {
		resolvedWorkspace = filepath.Clean(workspaceDir)
		if !filepath.IsAbs(resolvedWorkspace) {
			resolvedWorkspace, _ = filepath.Abs(resolvedWorkspace)
		}
	}
	resolvedWorkspace = filepath.Clean(resolvedWorkspace)

	cleanPath := filepath.Clean(requestedPath)
	if filepath.IsAbs(cleanPath) {
		cleanPath = strings.TrimPrefix(cleanPath, string(os.PathSeparator))
	}

	fullPathCandidate := filepath.Clean(filepath.Join(resolvedWorkspace, cleanPath))

	relPath, err := filepath.Rel(resolvedWorkspace, fullPathCandidate)
	if err != nil {
		return "", fmt.Errorf("access denied: cannot compute relative path")
	}

	if strings.HasPrefix(relPath, ".."+string(os.PathSeparator)) || relPath == ".." {
		return "", fmt.Errorf("access denied: path escapes workspace")
	}

	resolvedFinalPath, err := filepath.EvalSymlinks(fullPathCandidate)
	if err == nil {
		relPath, err = filepath.Rel(resolvedWorkspace, resolvedFinalPath)
		if err != nil {
			return "", fmt.Errorf("access denied: symlink resolution failed")
		}
		if strings.HasPrefix(relPath, ".."+string(os.PathSeparator)) || relPath == ".." {
			return "", fmt.Errorf("access denied: symlink target escapes workspace")
		}
		return resolvedFinalPath, nil
	}

	return fullPathCandidate, nil
}

